script:
for it in doc.items:
    if it.item_code:
        itemcode = it.item_code
        if it.gst_hsn_code:
            hsn = it.gst_hsn_code
            item = frappe.get_doc("Item",itemcode)
            name = item.name
            if itemcode == name:
                if hsn != item.gst_hsn_code:
                    item.gst_hsn_code = hsn
                    item.save()

if doc.stock_entry_type == "Material Receipt":
    if doc.reference_document != null and doc.reference_document != undefined:
        for it in doc.items:
            if it.material_request:
                if it.custom_rejected_qty > 0:
                    mat_req = frappe.get_doc("Material Request",it.material_request)
                    for mritem in mat_req.items:
                        comp_qty = mritem.ordered_qty
                        if comp_qty is None:
                            comp_qty = 0
                            comp_qty += it.custom_rejected_qty
                            frappe.db.set_value("Stock Entry Detail ",mritem.name,"ordered_qty",comp_qty)
                        else:
                            comp_qty += it.custom_rejected_qty
                            frappe.db.set_value("Stock Entry Detail",mritem.name,"ordered_qty",comp_qty)

# Server Script for Purchase Order (validate event)

invalid_items = []

for item in doc.items:
    if item.item_code:
        # Get the linked Item document
        item_doc = frappe.get_doc('Item', item.item_code)
        
        valid = False
        
        # Check warehouse child table in Item
        if item_doc.warehouse_:
            for row in item_doc.warehouse_:
                # Get the type, convert None to empty string and strip spaces
                type_value = (row.type or "").strip()
                if type_value in ["STK", "SLOW", "BLANK", "SPARE", ""]:
                    valid = True
                    break
        
        if not valid:
            invalid_items.append(f"{item.item_code} does not have a valid 'Type' (STK, SLOW, BLANK, SPARE, or empty) in Warehouse child table.")

if invalid_items:
    frappe.throw("Cannot submit Purchase Order:<br>" + "<br>".join(invalid_items))

if doc.sales_person:
    # Clear old child table
    doc.sales_team = []
        
        # Add new child row
    doc.append("sales_team", {
        "sales_person": doc.sales_person,
        "allocated_percentage": 100
    })
